import{_ as a,o as n,c as e,ak as i}from"./chunks/framework.DwHlt8HN.js";const o=JSON.parse('{"title":"以太网、ARP 协议、MAC 地址","description":"","frontmatter":{},"headers":[],"relativePath":"cs/network/ethernet-arp.md","filePath":"cs/network/ethernet-arp.md","lastUpdated":1774353797000}'),l={name:"cs/network/ethernet-arp.md"};function p(r,s,t,c,d,h){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="以太网、arp-协议、mac-地址" tabindex="-1">以太网、ARP 协议、MAC 地址 <a class="header-anchor" href="#以太网、arp-协议、mac-地址" aria-label="Permalink to “以太网、ARP 协议、MAC 地址”">​</a></h1><p>当你打开电脑连接网络时，有没有想过数据包是怎么从你的电脑发送到隔壁的打印机的？</p><p>它们不在同一个网络，不经过路由器，甚至不在「云端」——它们就在同一个房间里，靠以太网和 MAC 地址完成了这次传输。</p><h2 id="mac-地址-设备的「身份证号」" tabindex="-1">MAC 地址：设备的「身份证号」 <a class="header-anchor" href="#mac-地址-设备的「身份证号」" aria-label="Permalink to “MAC 地址：设备的「身份证号」”">​</a></h2><p>MAC 地址（Media Access Control Address）是网卡的物理地址，用于在数据链路层标识设备。它就像每个人的身份证号——全球唯一，终身不变。</p><h3 id="地址格式" tabindex="-1">地址格式 <a class="header-anchor" href="#地址格式" aria-label="Permalink to “地址格式”">​</a></h3><p>MAC 地址是 48 位（6 字节），通常用十六进制表示：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>08:00:27:3B:59:D3</span></span>
<span class="line"><span>或者</span></span>
<span class="line"><span>08-00-27-3B-59-D3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>前 24 位是<strong>厂商代码</strong>（OUI），由 IEEE 分配给各制造商。比如：</p><ul><li><code>08:00:27</code> 是 Oracle VirtualBox 的厂商代码</li><li><code>00:1A:2B</code> 是 Cisco 的厂商代码</li><li><code>F8:FF:C2</code> 是 Intel 的厂商代码</li></ul><p>后 24 位是<strong>厂商自行分配</strong>的序列号，确保同厂商的网卡也不会重复。</p><h3 id="特殊-mac-地址" tabindex="-1">特殊 MAC 地址 <a class="header-anchor" href="#特殊-mac-地址" aria-label="Permalink to “特殊 MAC 地址”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>FF:FF:FF:FF:FF:FF  → 广播地址，发送给所有设备</span></span>
<span class="line"><span>01:00:5E:xx:xx:xx  → 组播地址</span></span>
<span class="line"><span>00:00:00:00:00:00  → 未指定的地址</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>广播地址用于 ARP 请求——当你不知道目标 IP 对应的 MAC 地址时，就向全网广播这个 ARP 请求。</p><h3 id="mac-地址-vs-ip-地址" tabindex="-1">MAC 地址 vs IP 地址 <a class="header-anchor" href="#mac-地址-vs-ip-地址" aria-label="Permalink to “MAC 地址 vs IP 地址”">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>MAC 地址</th><th>IP 地址</th></tr></thead><tbody><tr><td>长度</td><td>48 位（6 字节）</td><td>IPv4: 32 位，IPv6: 128 位</td></tr><tr><td>作用层</td><td>数据链路层</td><td>网络层</td></tr><tr><td>是否可改</td><td>可修改（软件层面）</td><td>可配置，但本质是网络层标识</td></tr><tr><td>范围</td><td>局域网内唯一</td><td>全网唯一</td></tr><tr><td>分配方式</td><td>厂商烧录，理论上全球唯一</td><td>由 DHCP 或手动分配</td></tr></tbody></table><p>简单理解：<strong>IP 地址告诉你「去哪里」，MAC 地址告诉你「下一跳是谁」</strong>。</p><h2 id="以太网-局域网的王者" tabindex="-1">以太网：局域网的王者 <a class="header-anchor" href="#以太网-局域网的王者" aria-label="Permalink to “以太网：局域网的王者”">​</a></h2><p>以太网（Ethernet）是目前最主流的局域网技术，定义了数据链路层和物理层的标准。</p><h3 id="以太网帧结构" tabindex="-1">以太网帧结构 <a class="header-anchor" href="#以太网帧结构" aria-label="Permalink to “以太网帧结构”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌──────────┬────────────┬──────────┬──────────┬────────┬───────────┐</span></span>
<span class="line"><span>│  前导码   │  目的 MAC   │  源 MAC   │   类型    │  数据   │   CRC     │</span></span>
<span class="line"><span>│  8 字节   │   6 字节    │   6 字节  │  2 字节   │ 46-1500 │   4 字节  │</span></span>
<span class="line"><span>├──────────┼────────────┼──────────┼──────────┼────────┼───────────┤</span></span>
<span class="line"><span>│          │            │          │ 0x0800=IP │        │           │</span></span>
<span class="line"><span>│  1010... │  目的地址   │  源地址   │ 0x0806=ARP│ 负载   │ 校验和    │</span></span>
<span class="line"><span>└──────────┴────────────┴──────────┴──────────┴────────┴───────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li><strong>前导码</strong>：7 字节的 <code>10101010</code> + 1 字节的 <code>10101011</code>，用于时钟同步</li><li><strong>目的/源 MAC</strong>：各 6 字节，标识通信双方</li><li><strong>类型字段</strong>：标识上层协议，比如 <code>0x0800</code> 表示 IP 数据报，<code>0x0806</code> 表示 ARP</li><li><strong>数据</strong>：46-1500 字节，如果数据不足 46 字节会填充（padding）</li><li><strong>CRC</strong>：循环冗余校验，检测传输错误</li></ul><h3 id="以太网的工作原理" tabindex="-1">以太网的工作原理 <a class="header-anchor" href="#以太网的工作原理" aria-label="Permalink to “以太网的工作原理”">​</a></h3><p>以太网最初使用<strong>总线型拓扑</strong>，所有设备共享同一根电缆——就像老式电话总机，一根线被所有人共用。</p><p>这带来了一个问题：<strong>碰撞</strong>。两个设备同时发送数据，信号会撞在一起，都变成垃圾。</p><p>于是有了 <strong>CSMA/CD</strong>（载波侦听多路访问/碰撞检测）：</p><ol><li><strong>载波侦听</strong>：发送前先听总线是否空闲</li><li><strong>碰撞检测</strong>：发送时监测总线信号，发现碰撞立即停止</li><li><strong>退避算法</strong>：碰撞后随机等待一段时间再重试</li></ol><p>现代以太网基本用<strong>星型拓扑</strong>，通过交换机连接，碰撞域被隔离，每个端口独享带宽。但 CSMA/CD 的思想仍然影响了协议设计。</p><h2 id="arp-协议-ip-到-mac-的桥梁" tabindex="-1">ARP 协议：IP 到 MAC 的桥梁 <a class="header-anchor" href="#arp-协议-ip-到-mac-的桥梁" aria-label="Permalink to “ARP 协议：IP 到 MAC 的桥梁”">​</a></h2><p>ARP（Address Resolution Protocol）用于<strong>根据 IP 地址找到对应的 MAC 地址</strong>。</p><h3 id="为什么需要-arp" tabindex="-1">为什么需要 ARP？ <a class="header-anchor" href="#为什么需要-arp" aria-label="Permalink to “为什么需要 ARP？”">​</a></h3><p>IP 地址工作在网络层，MAC 地址工作在数据链路层。发送数据时：</p><ol><li>知道目标 IP，但不知道它的 MAC 地址</li><li>不知道 MAC 地址就无法封装以太网帧</li><li>ARP 就是来解决这个「鸡生蛋、蛋生鸡」的问题</li></ol><h3 id="arp-的工作流程" tabindex="-1">ARP 的工作流程 <a class="header-anchor" href="#arp-的工作流程" aria-label="Permalink to “ARP 的工作流程”">​</a></h3><p>假设你的电脑（IP: 192.168.1.100）要发送数据给 192.168.1.200，但不知道它的 MAC 地址。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一步：ARP 请求（广播）</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 以太网帧（广播）                                           │</span></span>
<span class="line"><span>│   目的 MAC: FF:FF:FF:FF:FF:FF（广播地址）                  │</span></span>
<span class="line"><span>│   源 MAC:   08:00:27:3B:59:D3（你自己的 MAC）              │</span></span>
<span class="line"><span>│   类型:     0x0806 (ARP)                                  │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│   ARP 请求内容：                                          │</span></span>
<span class="line"><span>│     &quot;谁是 192.168.1.200？请告诉我你的 MAC 地址&quot;             │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span> ↓ 发送给同一局域网的所有设备</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第二步：ARP 响应（单播）</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 以太网帧（单播）                                           │</span></span>
<span class="line"><span>│   目的 MAC: 08:00:27:3B:59:D3（请求方的 MAC）              │</span></span>
<span class="line"><span>│   源 MAC:   AA:BB:CC:DD:EE:FF（目标设备的 MAC）             │</span></span>
<span class="line"><span>│   类型:     0x0806 (ARP)                                  │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│   ARP 响应内容：                                          │</span></span>
<span class="line"><span>│     &quot;192.168.1.200 的 MAC 地址是 AA:BB:CC:DD:EE:FF&quot;        │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第三步：ARP 缓存</span></span>
<span class="line"><span>双方都会把对方的 IP-MAC 映射存入本地 ARP 缓存表，避免重复请求。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="查看-arp-缓存" tabindex="-1">查看 ARP 缓存 <a class="header-anchor" href="#查看-arp-缓存" aria-label="Permalink to “查看 ARP 缓存”">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux/Mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例输出：</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ? (192.168.1.1) at 00:11:22:33:44:55 [ether] on eth0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ? (192.168.1.200) at aa:bb:cc:dd:ee:ff [ether] on eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="arp-缓存过期" tabindex="-1">ARP 缓存过期 <a class="header-anchor" href="#arp-缓存过期" aria-label="Permalink to “ARP 缓存过期”">​</a></h3><p>ARP 缓存不是永久的，通常有 TTL（生存时间）。Windows 默认 20 分钟，Linux 默认 60 秒。</p><p>为什么要过期？因为设备可能换 IP、换网卡，甚至离开网络。缓存过期后重新 ARP 请求，保证数据发到正确设备。</p><h3 id="arp-欺骗-安全漏洞" tabindex="-1">ARP 欺骗：安全漏洞 <a class="header-anchor" href="#arp-欺骗-安全漏洞" aria-label="Permalink to “ARP 欺骗：安全漏洞”">​</a></h3><p>ARP 协议设计时没有考虑安全性，这是它的致命缺陷。</p><p><strong>ARP 欺骗原理</strong>：攻击者发送伪造的 ARP 响应，声称「目标 IP 的 MAC 是我的」，从而：</p><ul><li><strong>中间人攻击</strong>：截获双方通信</li><li><strong>断网攻击</strong>：发送伪造的 ARP 让目标无法上网</li><li><strong>会话劫持</strong>：偷取登录凭证</li></ul><p><strong>防御手段</strong>：</p><ul><li>静态 ARP 绑定（手工添加可信映射）</li><li>ARP 防火墙</li><li>交换机端口安全</li><li>检测 ARP 缓存异常</li></ul><h2 id="实际案例-同一局域网内的通信" tabindex="-1">实际案例：同一局域网内的通信 <a class="header-anchor" href="#实际案例-同一局域网内的通信" aria-label="Permalink to “实际案例：同一局域网内的通信”">​</a></h2><p>场景：你和室友在同一 WiFi 下，你向他发送文件。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>通信过程：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 你的电脑知道室友的 IP（比如 192.168.1.101）</span></span>
<span class="line"><span>2. 查询 ARP 缓存，找到了对应的 MAC 地址（假设 AA:BB:CC:DD:EE:FF）</span></span>
<span class="line"><span>3. 如果没找到，广播 ARP 请求，室友回复 ARP 响应</span></span>
<span class="line"><span>4. 你的电脑构造以太网帧：</span></span>
<span class="line"><span>   - 目的 MAC: AA:BB:CC:DD:EE:FF</span></span>
<span class="line"><span>   - 源 MAC:   08:00:27:3B:59:D3</span></span>
<span class="line"><span>   - 类型:     0x0800 (IP)</span></span>
<span class="line"><span>   - 数据:     IP 数据报（包含 TCP/UDP 等上层数据）</span></span>
<span class="line"><span>5. 交换机根据 MAC 地址表转发到室友的端口</span></span>
<span class="line"><span>6. 室友的网卡收到帧，检查目的 MAC 是自己的，接收并交给上层处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>整个过程不需要路由器，数据包直接通过交换机到达目标。</p><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>ARP 协议的工作原理是什么？为什么需要 ARP？</li><li>ARP 缓存的作用是什么？为什么要有 TTL？</li><li>MAC 地址和 IP 地址的区别和联系是什么？</li><li>什么是 ARP 欺骗？如何防御？</li><li>交换机和集线器的区别是什么？各工作在哪一层？</li><li>以太网帧的最大和最小长度是多少？为什么？</li></ul>`,55)])])}const u=a(l,[["render",p]]);export{o as __pageData,u as default};
